import React, { useState } from 'react';
import api from '../services/api';

function AddMeal({ friends, onMealAdded }) {
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [mealType, setMealType] = useState('lunch');
  const [payerId, setPayerId] = useState('');
  const [totalAmount, setTotalAmount] = useState('');
  const [splitType, setSplitType] = useState('equal');
  const [selectedFriends, setSelectedFriends] = useState([]);
  const [customAmounts, setCustomAmounts] = useState({});
  const [loading, setLoading] = useState(false);

  const handleFriendToggle = (friendId) => {
    if (selectedFriends.includes(friendId)) {
      setSelectedFriends(selectedFriends.filter(id => id !== friendId));
      const newCustomAmounts = { ...customAmounts };
      delete newCustomAmounts[friendId];
      setCustomAmounts(newCustomAmounts);
    } else {
      setSelectedFriends([...selectedFriends, friendId]);
      if (splitType === 'custom') {
        setCustomAmounts({ ...customAmounts, [friendId]: 0 });
      }
    }
  };

  const handleCustomAmountChange = (friendId, amount) => {
    setCustomAmounts({ ...customAmounts, [friendId]: parseFloat(amount) || 0 });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (!payerId || !totalAmount || selectedFriends.length === 0) {
      alert('Please fill all fields and select at least one friend');
      return;
    }

    setLoading(true);
    
    let participants = [];
    if (splitType === 'equal') {
      participants = selectedFriends;
    } else {
      // Validate custom amounts sum to total
      const totalCustom = Object.values(customAmounts).reduce((sum, val) => sum + val, 0);
      if (Math.abs(totalCustom - parseFloat(totalAmount)) > 0.01) {
        alert(`Custom amounts sum to ${totalCustom}, but total is ${totalAmount}. Please adjust.`);
        setLoading(false);
        return;
      }
      participants = selectedFriends.map(friendId => ({
        friend_id: friendId,
        amount: customAmounts[friendId]
      }));
    }

    const mealData = {
      date,
      meal_type: mealType,
      payer_id: parseInt(payerId),
      total_amount: parseFloat(totalAmount),
      split_type: splitType,
      participants
    };

    try {
      await api.addMeal(mealData);
      alert('Meal added successfully!');
      // Reset form
      setPayerId('');
      setTotalAmount('');
      setSelectedFriends([]);
      setCustomAmounts({});
      onMealAdded();
    } catch (error) {
      console.error('Error adding meal:', error);
      alert('Error adding meal');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div>
      <h2>Add New Meal</h2>
      <form onSubmit={handleSubmit}>
        <div className="form-group">
          <label>Date:</label>
          <input
            type="date"
            value={date}
            onChange={(e) => setDate(e.target.value)}
            required
          />
        </div>

        <div className="form-group">
          <label>Meal Type:</label>
          <select value={mealType} onChange={(e) => setMealType(e.target.value)}>
            <option value="breakfast">Breakfast</option>
            <option value="lunch">Lunch</option>
          </select>
        </div>

        <div className="form-group">
          <label>Who paid?</label>
          <select value={payerId} onChange={(e) => setPayerId(e.target.value)} required>
            <option value="">Select person</option>
            {friends.map(friend => (
              <option key={friend.id} value={friend.id}>{friend.name}</option>
            ))}
          </select>
        </div>

        <div className="form-group">
          <label>Total Amount ($):</label>
          <input
            type="number"
            step="0.01"
            value={totalAmount}
            onChange={(e) => setTotalAmount(e.target.value)}
            required
          />
        </div>

        <div className="form-group">
          <label>Split Type:</label>
          <select value={splitType} onChange={(e) => setSplitType(e.target.value)}>
            <option value="equal">Equal Split</option>
            <option value="custom">Custom Split</option>
          </select>
        </div>

        <div className="form-group">
          <label>Who ate together?</label>
          <div className="friend-checkboxes">
            {friends.map(friend => (
              <div key={friend.id} className="friend-checkbox">
                <label>
                  <input
                    type="checkbox"
                    checked={selectedFriends.includes(friend.id)}
                    onChange={() => handleFriendToggle(friend.id)}
                  />
                  {friend.name}
                </label>
                {splitType === 'custom' && selectedFriends.includes(friend.id) && (
                  <input
                    type="number"
                    step="0.01"
                    placeholder="Amount"
                    value={customAmounts[friend.id] || ''}
                    onChange={(e) => handleCustomAmountChange(friend.id, e.target.value)}
                    style={{ marginLeft: '10px', width: '100px' }}
                  />
                )}
              </div>
            ))}
          </div>
        </div>

        <button type="submit" disabled={loading}>
          {loading ? 'Adding...' : 'Add Meal'}
        </button>
      </form>
    </div>
  );
}

export default AddMeal;
